import styles from "./Activity.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import { connect } from "react-redux";
import buildActions from "../../../store/actions";
import { InjectLocale } from "../../../../../decorators/locale";
import { isIE, isSafari, isMobile } from "../../../../../../common/constants/user-agent";
import AdaHelper from "../../../../common/components/AdaHelper/AdaHelper";
import ActivityHeader from "../../../../common/components/ActivityHeader/ActivityHeader";
import SvgElement from "../../../../common/components/SvgElement/SvgElement";
import SvgImage from "../../../../common/components/SvgImage/SvgImage";
import Popup from "../../../../common/components/Popup/Popup";
import BaseSpot from "../../../../common/components/BaseSpot/BaseSpot";
import { Key } from "../../../../../../common/constants/keyboard";
import { sleep } from "../../../../../../common/utils/async";
import Controls from "../Controls/Controls";

@connect(
  state => ({
    activityId: state.id,
    activityName: state.name,
    studentInstruction: state.studentInstruction,
    spots: state.spots,
    viewBox: {
      ...state.viewBox,
      x: state.viewBox.left,
      y: state.viewBox.top
    },
    image: state.image,
    showHints: state.showHints
  }),
  buildActions
)
@InjectLocale("Activity")
class Activity extends PureComponent {
  static propTypes = {
    activityAlign: PropTypes.object,
    activityId: PropTypes.number.isRequired,
    activityName: PropTypes.string.isRequired,
    studentInstruction: PropTypes.string.isRequired,
    spots: PropTypes.array.isRequired,
    viewBox: PropTypes.object.isRequired,
    image: PropTypes.object.isRequired,
    showHints: PropTypes.bool.isRequired
  };

  state = this.initialState;
  spotsRef = [];

  playerStyle = {
    ...this.props.activityAlign
  };

  componentDidMount() {
    if (isIE || isSafari) {
      this.onResize();
      window.addEventListener("resize", this.onResize);
    }
  }

  componentWillUnmount() {
    if (isIE || isSafari) {
      window.removeEventListener("resize", this.onResize);
    }
  }

  onResize = () => {
    this.setState({
      svgWidth: this.refs.svgWrapper.clientWidth
    });
  };

  async updateAriaText(ariaText) {
    await sleep(0);
    this.setState({
      ariaText
    });
  }

  onSVGMouseDown = () => {
    this.updatePopup({
      show: false
    });
  };

  updatePopup = data => {
    this.refs.popup.update(data, this.refs.player);
  };

  toggleHotspots = () => {
    const { showHotspots } = this.state;
    const ariaText = showHotspots ? this.locale.hide_hotspots : this.locale.show_hotspots;

    this.setState({
      showHotspots: !showHotspots,
      ariaText: ""
    });

    this.updateAriaText(ariaText);
  };

  onActivityKeyDown = e => {
    switch (e.keyCode) {
      case Key.S:
        if (e.altKey && this.props.showHints) {
          e.preventDefault();
          this.toggleHotspots();
        }
        break;
      default:
    }
  };

  onActivityTouchEnd = e => {
    const { popup } = this.refs;
    const { popupContainer } = popup.refs;
    if (popup.show && !popupContainer.contains(e.target)) {
      this.spotsRef[this.currentKey].setState({
        popUpShown: false
      });
      this.updatePopup({ show: false });
    }
  };

  get initialState() {
    return {
      showHotspots: false,
      ariaText: ""
    };
  }

  get svgSize() {
    const { image } = this.props;
    let svgSize = {
      maxWidth: image.width,
      maxHeight: image.height
    };

    if ((isIE || isSafari) && this.state.svgWidth) {
      svgSize.width = this.state.svgWidth;
      svgSize.height = (this.state.svgWidth / image.width) * image.height;
    }

    return svgSize;
  }

  focusCurrentSpot = () => {
    this.spotsRef[this.currentKey].setFocus();
  };

  focusNextSpot = () => {
    if (this.currentKey + 1 < this.spotsRef.length) {
      this.spotsRef[this.currentKey + 1].setFocus();
    } else {
      this.refs.popup.setState({
        show: false
      });
    }
    this.spotsRef[this.currentKey].setState({
      visible: false,
      popUpShown: false
    });
  };

  focusPopup = key => {
    this.currentKey = key;
    this.refs.popup.focusPopup();
  };

  popUpLeave = () => {
    if (this.currentKey) {
      const { popUpShown } = this.spotsRef[this.currentKey].state;
      if (popUpShown) {
        this.spotsRef[this.currentKey].setState({
          popUpShown: false
        });
      }
    }
  };

  spotSelected = key => {
    this.currentKey = key;
  };

  blurHandler = () => {
    if (this.currentKey) {
      if (this.spotsRef[this.currentKey]) {
        this.spotsRef[this.currentKey].setState({
          popUpShown: false,
          visible: false
        });
        this.updatePopup({ show: false });
      }
    }
  };

  render() {
    const { studentInstruction, activityName, activityId, viewBox, image, spots } = this.props;

    return (
      <section
        tabIndex="0"
        className={styles.container}
        onKeyDown={this.onActivityKeyDown}
        onTouchEnd={this.onActivityTouchEnd}
        onBlur={this.blurHandler}
      >
        <AdaHelper ariaText={this.state.ariaText} />
        <ActivityHeader activityName={activityName} studentInstruction={studentInstruction} />
        <div ref="player" style={this.playerStyle} className={styles.player}>
          {this.props.showHints && <Controls toggleHotspots={this.toggleHotspots} />}
          <div role="application" ref="svgWrapper" className={styles.body}>
            <SvgElement viewBox={viewBox} {...this.svgSize} onMouseDown={this.onSVGMouseDown}>
              <SvgImage viewBox={viewBox} url={image.url} />
              {spots.map((item, key) => (
                <BaseSpot
                  ref={ref => (this.spotsRef[key] = ref)}
                  focusPopup={this.focusPopup}
                  togglePopup={true}
                  key={key}
                  spotNumber={key}
                  activityId={activityId}
                  mode="explore"
                  visible={this.state.showHotspots}
                  updateHandler={this.updatePopup}
                  spotSelected={this.spotSelected}
                  {...item}
                />
              ))}
            </SvgElement>
          </div>
          <Popup
            focusCurrentSpot={this.focusCurrentSpot}
            focusNextSpot={this.focusNextSpot}
            ref="popup"
            activityId={activityId}
            popUpLeave={!isMobile ? this.popUpLeave : null}
          />
        </div>
      </section>
    );
  }
}

export default Activity;
